def max_profit(prices, k):
    if not prices or k < 1:
        return 0
    n = len(prices)
    if k >= n // 2:
        return max(prices) - min(prices)
    dp = [[0] * (k + 1) for _ in range(n)]
    for i in range(1, n):
        for j in range(1, k + 1):
            dp[i][j] = max(dp[i - 1][j], prices[i] - prices[i - 1] + dp[i - 1][j - 1])
    return dp[-1][-1]

