def get_max_occuring_char(input_str):
    char_count = {}
    max_count = 0
    max_char = ""
    for char in input_str:
        if char not in char_count:
            char_count[char] = 1
        else:
            char_count[char] += 1
        if char_count[char] > max_count:
            max_count = char_count[char]
            max_char = char
    return max_char

