def is_subset_sum(my_list, target, current_sum=0):
    if not my_list:
        return False
    if current_sum == target:
        return True
    if current_sum > target:
        return False
    return is_subset_sum(my_list[1:], target, current_sum + my_list[0]) or is_subset_sum(my_list[1:], target, current_sum)

